class Solution {
    public int longestDecomposition(String text) {
        int k = 1;
        int[] count = new int[26];
        for (int i = 0; i < text.length(); i++) {
            count[text.charAt(i) - 'a']++;
        }
        for (int i = 0; i < text.length(); i++) {
            count[text.charAt(i) - 'a']--;
            if (count[text.charAt(i) - 'a'] == 0) {
                k++;
            }
        }
        return k;
    }
}
